昨年、SDKを設計し、イベントのパッキング処理を担当しました。外部に対してはクラスインターフェースを提供し、サービス初期化時に呼び出し元が対応するクラスを実装し、オブジェクトポインタをモジュールに渡します。
C11にも触れており、好奇心で猫が死ぬように、これらのインターフェースをlambda関数オブジェクトのコールバックとして実現するとどうなるのか、純粋仮想関数インターフェース定義方法と比較して、より柔軟になるのか試してみようと考えました。
疑問が生じました。2つの異なる構文、性能面からどちらが速いのか不明です。コンパイラ原理は理解していないので、コードを書いて試してみます。
はじめに オンラインのURLで、異なるコンパイラを選択したり、コンパイルパラメータを設定したり、linuxプラットフォーム上でコードを実行したり、対応するアセンブリコードを確認したりできます。
https://wandbox.org/：時々技術検証のために、ウェブ上で小さなコードスニペットを実行するのは非常に便利です。 https://godbolt.org/：異なる色でアセンブリコードと対応するコードを区別できるため、ローカルのデバッガよりもさらに便利です。 本文 標準委員会が定める文法規則について、コンパイルレベルにおいてどのように実現するかは、各社のコンパイラに依存します。この点については、特にマイクロソフトのコンパイラは非常に優れていると言わざるを得ません。文法糖衣は万能ではなく、コールバックインターフェースが少ないこと、ラムダ式を使用することでより便利であり、空のコールバック関数インターフェースを定義する必要がないことが挙げられます。コールバックインターフェースの種類が多い場合には、従来の仮想関数の方がビジネスインターフェースの統一に有利です。
Windowsプラットフォームでは、両者の性能はほぼ同等で、大きな違いはありません。 Linuxプラットフォームでは、仮想関数とラムダ式を比較すると、単回りは1.35ns増加します。 通常のビジネスシステム開発においては、この程度の性能損失は無視できる範囲内であり、ラムダ式を使用することで、設計面での利便性が向上します。特に多重信号処理を行う場合には顕著であり、底层にはイベントトリガーがあり、ログ出力が必要な場合、ログオブジェクトへの処理関数を呼び出します。より多くのビジネス処理インターフェースが必要な場合には、底层でvectorにラムダオブジェクトを保存し、イベントトリガー時に順次呼び出しを行います。これはQTのシグナルとスロットに類似しており、ログ、監視、ビジネス1、ビジネス2といったものが完全に疎結合です。 コード カウンター：1000000 時間：3966us カウンター：1000000 時間：5316us #include &lt;iostream&gt; #include &lt;chrono&gt; #include &lt;memory&gt; #include &lt;functional&gt; #include &lt;atomic&gt; #include &lt;string&gt; std::atomic_int64_t カウンター = 0; // 回呼インターフェースを定義 class UserInterface { public: virtual void name() = 0; virtual void full_name() = 0; }; class User : public UserInterface { public: void name() {} void full_name() { カウンター++; } }; void to_string(UserInterface* user) { user-&gt;name(); user-&gt;full_name(); } using name_handler = std::function&lt;void()&gt;; using full_name_handler = std::function&lt;void()&gt;; class Test { name_handler name_; full_name_handler full_name_; public: void set_name_handler(name_handler name) { name_ = name; } void set_full_name_handler(full_name_handler full_name) { full_name_ = full_name; } void to_string() { name_(); full_name_(); } }; int main() { User user; auto start = std::chrono::high_resolution_clock::now(); for (int i = 0; i &lt; 1000000; i++) { to_string(&amp;user); } auto end = std::chrono::high_resolution_clock::now(); std::cout &lt;&lt; &#34;カウンター： &#34; &lt;&lt; カウンター &lt;&lt; std::endl; std::cout &lt;&lt; &#34;時間： &#34; &lt;&lt; std::chrono::duration_cast&lt;std::chrono::microseconds&gt;(end - start).count() &lt;&lt; &#34;us&#34; &lt;&lt; std::endl; counter = 0; auto name = []() {}; auto full_name = []() { カウンター++; }; Test test; test.set_name_handler(name); test.set_full_name_handler(full_name); start = std::chrono::high_resolution_clock::now(); for (int i = 0; i &lt; 1000000; i++) { test.to_string(); } end = std::chrono::high_resolution_clock::now(); std::cout &lt;&lt; &#34;カウンター： &#34; &lt;&lt; カウンター &lt;&lt; std::endl; std::cout &lt;&lt; &#34;時間： &#34; &lt;&lt; std::chrono::duration_cast&lt;std::chrono::microseconds&gt;(end - start).count() &lt;&lt; &#34;us&#34; &lt;&lt; std::endl; return 0; } 付録 gist.githubusercontent.com/benloong/8050171/raw/fa577ec923b460862078b8b40233a42a1c619eeb/functionperformance.cpp のようなコードスニペットを参考にしました。 #include &lt;iostream&gt; #include &lt;chrono&gt; #include &lt;memory&gt; #include &lt;functional&gt; using namespace std; using namespace std::chrono; class Base { public: Base(){} virtual ~Base(){} virtual int func(int i) = 0; }; class Derived : public Base { public: Derived(int base = 10) : base{base} { } ~Derived(){} virtual int func(int i) { return i*base; } private: int base; }; struct Func { int base; int operator()(int i) { return i*base; } Func(int base) : base {base} { } }; const int base = 10; int calculate(int i) { return base*i; } int main() { const int num = 10000; Base *p = new Derived{10}; int total = 0; auto start = high_resolution_clock::now(); for (int i = 0; i &lt; num; ++i) { total += p-&gt;func(i); } auto end = high_resolution_clock::now(); std::cout&lt;&lt;&#34;result: &#34;&lt;&lt;total&lt;&lt;&#34;
